class CountIntervals {
public:
    CountIntervals() {
        total = 0;
    }

    void add(int left, int right) {
        int l = left, r = right;
        while (l <= r) {
            int x = l / 64;
            int y = l % 64;
            if (!(mask[x] & (1LL << y))) {
                mask[x] |= (1LL << y);
                total++;
            }
            l++;
        }
    }

    int count() {
        return total;
    }
private:
    int total;
    vector<long long> mask(1e6 / 64 + 1, 0);
};
```
